import microcoapy
from machine import Pin
from dht import DHT22

# Initialize DHT22 sensor
dht22 = DHT22(Pin(4))

# Initialize light actuator
light = Pin(2, Pin.OUT)

def tempGetHandler(packet, senderIp, senderPort):
    dht22.measure()
    temp = dht22.temperature()
    return microcoapy.CoapPacket(messageType=microcoapy.COAP_TYPE_ACK, code=microcoapy.COAP_CODE_205_CONTENT, payload=str(temp))

def lightPutHandler(packet, senderIp, senderPort):
    lightValue = int(packet.toString())
    light.value(lightValue)
    return microcoapy.CoapPacket(messageType=microcoapy.COAP_TYPE_ACK, code=microcoapy.COAP_CODE_204_CHANGED)

# Create CoAP server
server = microcoapy.Coap()

# Add resources
server.addResource("/sensors/temp", tempGetHandler, microcoapy.COAP_METHOD_GET)
server.addResource("/actuators/light", lightPutHandler, microcoapy.COAP_METHOD_PUT)

# Start CoAP server
server.start()